package residentevm
import("bytes";"testing")
func TestLogicalRoundTripDeterministic(t *testing.T){in:=&ResidentEvmDeltaV1{WireVersion:1,SchemaVersion:1,LogicalSequence:7,Record:&ResidentEvmDeltaV1_MessageCommitted{MessageCommitted:&MessageCommitted{MessageHash:bytes.Repeat([]byte{7},32),Mutations:[]*Mutation{{Address:bytes.Repeat([]byte{1},20),Slot:bytes.Repeat([]byte{2},32),Value:bytes.Repeat([]byte{3},32)}}}}};b,err:=MarshalLogical(in);if err!=nil{t.Fatal(err)};var out ResidentEvmDeltaV1;if err=UnmarshalLogical(b,&out);err!=nil{t.Fatal(err)};got,err:=MarshalLogical(&out);if err!=nil||!bytes.Equal(got,b){t.Fatalf("not deterministic: %v",err)}}
func TestFrameRoundTripAndChecksum(t *testing.T){payload,_:=MarshalLogical(&ResidentEvmDeltaV1{WireVersion:1,SchemaVersion:1,Record:&ResidentEvmDeltaV1_Gap{Gap:&Gap{GapEpoch:1}}});f,err:=EncodeFrame(Frame{WireVersion:1,SchemaVersion:1,ChunkCount:1,LogicalSequence:4,Payload:payload});if err!=nil{t.Fatal(err)};got,err:=DecodeFrame(f);if err!=nil||!bytes.Equal(got.Payload,payload){t.Fatalf("frame: %v",err)};f[len(f)-1]^=1;if _,err=DecodeFrame(f);err==nil{t.Fatal("checksum corruption accepted")}}
func TestFrameRejectsTrailingAndMixedMetadata(t *testing.T){f,_:=EncodeFrame(Frame{WireVersion:1,SchemaVersion:1,ChunkCount:1,Payload:[]byte{1}});if _,err:=DecodeFrame(append(f,0));err==nil{t.Fatal("trailing bytes accepted")};g,_:=EncodeFrame(Frame{WireVersion:1,SchemaVersion:1,ChunkCount:2,ChunkIndex:0,LogicalSequence:1,Payload:[]byte{1}});h,_:=EncodeFrame(Frame{WireVersion:1,SchemaVersion:1,ChunkCount:2,ChunkIndex:1,LogicalSequence:2,Payload:[]byte{2}});if _,err:=ReassembleFrames([][]byte{g,h});err==nil{t.Fatal("mixed sequence accepted")}}
